<?php namespace App\Repositories\Certificate;use App\Repositories\BaseRepository;use App\Models\Certificate\CertificateType;use Illuminate\Database\Eloquent\Collection;class CertificateTypeRepository extends BaseRepository{    public function __construct(CertificateType $model)    {        $this->model = $model;        parent::__construct($model);    }    public function findByName(string $name): ?CertificateType    {        return $this->query()->where('name', $name)->first();    }    public function findByCode(string $code): ?CertificateType    {        return $this->query()->where('code', $code)->first();    }    public function getActiveTypes(): Collection    {        return $this->query()->where('is_active', true)->get();    }    public function getByCategory(string $category): Collection    {        return $this->findByField('category', $category);    }    public function searchTypes(string $keyword): Collection    {        return $this->query()->where('name', 'like', "%{$keyword}%")->orWhere('code', 'like', "%{$keyword}%")->orWhere('description', 'like', "%{$keyword}%")->get();    }    public function getTypeWithTemplates(int $typeId): ?CertificateType    {        return $this->query()->with('templates')->findOrFail($typeId);    }}